create table if not exists public.sales_order_sequences(id uuid primary key default gen_random_uuid(),organization_id uuid not null,workspace_id uuid,year integer not null,prefix text not null default 'SO',last_value bigint not null default 0,unique(organization_id,workspace_id,year,prefix));
create table if not exists public.sales_orders(id uuid primary key default gen_random_uuid(),organization_id uuid not null,workspace_id uuid,order_number text not null,customer_id uuid,contact_id uuid,source_quote_id uuid,warehouse_id uuid,status text not null default 'draft' check(status in('draft','confirmed','picking','packed','partially_shipped','shipped','completed','cancelled')),order_date date not null default current_date,requested_delivery_date date,currency text not null default 'EUR',notes text not null default '',metadata jsonb not null default '{}'::jsonb,deleted_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now(),unique(organization_id,order_number));
create table if not exists public.sales_order_lines(id uuid primary key default gen_random_uuid(),sales_order_id uuid not null references public.sales_orders(id) on delete cascade,product_id uuid,variant_id uuid,warehouse_id uuid,description text not null default '',sku text not null default '',position integer not null default 1,quantity numeric(14,3) not null default 1,reserved_quantity numeric(14,3) not null default 0,fulfilled_quantity numeric(14,3) not null default 0,unit_price numeric(14,4) not null default 0,unit_cost numeric(14,4) not null default 0,discount_percent numeric(7,4) not null default 0,tax_rate numeric(7,4) not null default 0,metadata jsonb not null default '{}'::jsonb,created_at timestamptz not null default now());
create table if not exists public.sales_order_status_history(id uuid primary key default gen_random_uuid(),sales_order_id uuid not null references public.sales_orders(id) on delete cascade,from_status text,to_status text not null,reason text,actor_id uuid,created_at timestamptz not null default now());
create index if not exists sales_orders_org_status_idx on public.sales_orders(organization_id,status) where deleted_at is null;
create index if not exists sales_order_lines_order_idx on public.sales_order_lines(sales_order_id,position);
create or replace function public.sales_orders_next_number(p_organization_id uuid,p_workspace_id uuid default null,p_prefix text default 'SO',p_year integer default extract(year from current_date)::integer) returns text language plpgsql security definer as $$ declare v bigint; begin insert into public.sales_order_sequences(organization_id,workspace_id,year,prefix,last_value) values(p_organization_id,p_workspace_id,p_year,p_prefix,1) on conflict(organization_id,workspace_id,year,prefix) do update set last_value=public.sales_order_sequences.last_value+1 returning last_value into v; return p_prefix||'-'||p_year||'-'||lpad(v::text,6,'0'); end $$;
alter table public.sales_orders enable row level security; alter table public.sales_order_lines enable row level security; alter table public.sales_order_status_history enable row level security; alter table public.sales_order_sequences enable row level security;
create policy sales_orders_tenant on public.sales_orders using(exists(select 1 from public.organization_memberships m where m.organization_id=sales_orders.organization_id and m.user_id=auth.uid() and m.status='active')) with check(exists(select 1 from public.organization_memberships m where m.organization_id=sales_orders.organization_id and m.user_id=auth.uid() and m.status='active'));
create policy sales_order_lines_tenant on public.sales_order_lines using(exists(select 1 from public.sales_orders o join public.organization_memberships m on m.organization_id=o.organization_id where o.id=sales_order_lines.sales_order_id and m.user_id=auth.uid() and m.status='active')) with check(exists(select 1 from public.sales_orders o join public.organization_memberships m on m.organization_id=o.organization_id where o.id=sales_order_lines.sales_order_id and m.user_id=auth.uid() and m.status='active'));
create policy sales_order_history_tenant on public.sales_order_status_history using(exists(select 1 from public.sales_orders o join public.organization_memberships m on m.organization_id=o.organization_id where o.id=sales_order_status_history.sales_order_id and m.user_id=auth.uid() and m.status='active')) with check(exists(select 1 from public.sales_orders o join public.organization_memberships m on m.organization_id=o.organization_id where o.id=sales_order_status_history.sales_order_id and m.user_id=auth.uid() and m.status='active'));
create policy sales_order_sequences_tenant on public.sales_order_sequences using(exists(select 1 from public.organization_memberships m where m.organization_id=sales_order_sequences.organization_id and m.user_id=auth.uid() and m.status='active')) with check(exists(select 1 from public.organization_memberships m where m.organization_id=sales_order_sequences.organization_id and m.user_id=auth.uid() and m.status='active'));